    ('PSY-C 309', 'CAREERS MODULE 3 - PRACTICAL HIGH GEAR EXPLORATION', '9020', 'Closed', NULL, 'WB WEB', 'Kimberly Ross', 0, NULL, 'Activity', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Third module of the career exploration sequence, focusing on practical skills for career exploration, including job search techniques and teamwork with peers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('PSY-C 309', 'CAREERS MODULE 3 - PRACTICAL HIGH GEAR EXPLORATION', '12373', 'Closed', NULL, 'WB WEB', 'Serena Ostrander', 0, NULL, 'Activity', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Third module of the career exploration sequence, focusing on practical skills for career exploration, including job search techniques and teamwork with peers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('PSY-G 512', 'COUNSELING APPROACHES WITH ADDICTIONS', '33483', 'Class Status', NULL, 'OL ONLINE', 'Debolina Ghosh', 7, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course evaluates treatment modalities of substance-related and addictive disorders contained in the current edition of the Diagnostic and Statistical Manual of Mental Disorders. Special attention is given to treatment readiness, assessment, treatment planning, counseling modalities, psychopharmacology, client education, case management, crisis intervention, referral, consultation, community resources, and reports and record keeping. Recent issues in addiction and recovery, evidence-based practices, and co-occurring disorders are discussed. Students are expected to engage in active learning projects.', ARRAY[]::TEXT[], NULL),
    ('PSY-G 901', 'ADVANCED RESEARCH', '2903', 'Class Status', NULL, NULL, 'Karin James', 27, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('PSY-G 901', 'ADVANCED RESEARCH', '9944', 'Class Status', NULL, NULL, 'Karin James', 20, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
