    ('PSY-P 304', 'SOCIAL PSYCHOLOGY AND INDIVIDUAL DIFFERENCES', '6230', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 104', 'Kurt Hugenberg', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A foundations course illustrating how psychological questions and problems can be addressed from the social, group, and individual differences level of analysis.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('PSY-P 315', 'DEVELOPMENTAL PSYCHOLOGY', '12126', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PY 101', 'Lisa Thomassen', 2, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'An introduction to how and why behavior changes over time. The theories and methods used to study behavioral change in both human and non-human models. Topics include development in perception, movement, language, cognition, and social/emotional behavior.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('PSY-P 318', 'FOUNDATIONS OF CLINICAL SCIENCE', '7015', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PY 226', 'Emma Schiestl', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'A foundational course that examines clinical phenomena and their treatments from a scientific perspective. Emphasizes critical thinking and its importance in clinical practice. Focuses on questions, methods, findings, and applications drawn from clinical science and on ways to apply scientific knowledge and approaches to clinical practices.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 319', 'THE PSYCHOLOGY OF PERSONALITY', '13502', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GY 1045', 'Allan Roberts', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Methods and results of scientific study of personality. Basic concepts of personality traits and their measurements; developmental influences; problems of integration.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
