    ('PSY-P 337', 'CLINICAL NEUROSCIENCE', '8065', 'Closed', 'W Wednesday 4:00 PM–5:15 PM', 'PY 101', 'Krista Wisner', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Psychological disorders such as depression and autism exact a huge toll in human suffering and social costs. This course surveys the role of disturbed neural mechanisms on the development of psychological disorders. Methods for investigating the relationship between a disorder and proposed mechanism, will be critically evaluated.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 346', 'NEUROSCIENCE', '4755', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WY 005', 'Anna Kalinovsky', 18, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'A survey of contemporary neuroscience, examining the neural basis of behavior with approaches including molecular, cellular, developmental, cognitive, and behavioral neuroscience. Sensory and motor function, learning and memory, and other behaviors are considered using anatomical, physiological, behavioral, biochemical, and genetic approaches, providing a balanced view or neuroscience.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 346', 'NEUROSCIENCE', '11344', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PY 101', 'Dale Sengelaub', 21, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'A survey of contemporary neuroscience, examining the neural basis of behavior with approaches including molecular, cellular, developmental, cognitive, and behavioral neuroscience. Sensory and motor function, learning and memory, and other behaviors are considered using anatomical, physiological, behavioral, biochemical, and genetic approaches, providing a balanced view or neuroscience.', ARRAY['Class uses IU eTexts'], NULL),
