    ('PSY-P 357', 'TOPICS IN PSYCHOLOGY', '30041', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PY 226', 'Gregory Koop', 9, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Introduction to fundamental issues, integrative approaches and real world applications of psychology. Examples include investigating a topic from a developmental, cognitive, individual difference, and neuroscience perspective; or examining addiction from a clinical, developmental, social, and neuroscience point of view.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 357', 'TOPICS IN PSYCHOLOGY', '30042', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PY 226', 'Benjamin Motz', 10, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Introduction to fundamental issues, integrative approaches and real world applications of psychology. Examples include investigating a topic from a developmental, cognitive, individual difference, and neuroscience perspective; or examining addiction from a clinical, developmental, social, and neuroscience point of view.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 357', 'TOPICS IN PSYCHOLOGY', '13616', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PY 109', 'Thomas Busey', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Introduction to fundamental issues, integrative approaches and real world applications of psychology. Examples include investigating a topic from a developmental, cognitive, individual difference, and neuroscience perspective; or examining addiction from a clinical, developmental, social, and neuroscience point of view.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 366', 'CONSUMER PSYCHOLOGY', '12270', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PY 226', 'Edward Hirt', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Examines the emotional, cognitive, and behavioral responses that precede, determine, or follow the purchase and consumption of goods and services. Provides a broad understanding of buying behavior by looking at fundamental issues within consumer behavior from a social psychological framework.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 375', 'INTIMATE RELATIONSHIPS', '14838', 'Closed', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'PY 226', 'Katie Adams', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Focuses on the social psychology of relationships including marriage, divorce, human sexuality, jealousy, communication, and friendships.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 386', 'SOCIAL NEUROSCIENCE', '8598', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PY 109', 'Aina Puce', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Didactic lectures by faculty, laboratory demonstrations, and seminars/class discussions led by students examine non-verbal communication and mind-brain-body relationships. Topics include reading faces and bodies, microexpressions, emotion and emotional contagion. Assessment is based on presentations, student-led discussions, participation in class, and written critiques on selected readings.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 407', 'DRUGS AND THE NERVOUS SYSTEM', '12128', 'Closed', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'PY 111', 'Kendra Bunner', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Introduction to the major psychoactive drugs and how they act upon the brain to influence behavior. The role of drugs as therapeutic agents for various clinical disorders and as probes to provide insight into brain function also is discussed.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 410', 'DEVELOPMENT OF THE BRAIN AND BEHAVIOR', '12129', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PY 230', 'Jeffrey Alberts', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Examination of the interaction of the developing brain with the behavior it mediates. Cellular systems and organismal levels of analysis will all be considered in the organization of structure function relationships in the neural basis of behavior.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 411', 'NEURAL BASES OF LEARNING AND MEMORY', '34530', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PY 228', 'Sydney Trask', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Comprehensive survey of theories and data concerned with neural correlates of associative and non-associative forms of learning and memory. Vertebrate and invertebrate model systems and preparations as well as data obtained from the human neuropsychology literature will be studied.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 421', 'LABORATORY IN SOCIAL PSYCHOLOGY', '5973', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PY 286', 'Katie Adams', 4, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Research methodology in the study of social behavior.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 421', 'LABORATORY IN SOCIAL PSYCHOLOGY', '12130', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PY 286', 'Antonio Viera', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Research methodology in the study of social behavior.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 425', 'BEHAVIOR DISORDERS OF CHILDHOOD AND ADOLESCENCE', '30074', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PY 109', 'Brian D''Onofrio', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'A survey of major behavior disorders, with emphasis on empirical research and clinical description relative to etiology, assessment, prognosis, and treatment.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 426', 'LABORATORY IN BEHAVIORAL NEUROSCIENCE', '7243', 'Class Status', 'Th Thursday 11:00 AM–2:00 PM', 'PY 396', 'Kendra Bunner', 1, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experiments with and demonstrations of contemporary approaches in behavioral neuroscience.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 426', 'LABORATORY IN BEHAVIORAL NEUROSCIENCE', '9856', 'Class Status', 'ThF Thursday, Friday 1:00 PM–4:30 PM', 'PY 482', 'Preston Garraghty', 2, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experiments with and demonstrations of contemporary approaches in behavioral neuroscience.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 426', 'LABORATORY IN BEHAVIORAL NEUROSCIENCE', '9853', 'Closed', 'MF Monday, Friday 1:00 PM–4:30 PM', 'PY 482', 'Preston Garraghty', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experiments with and demonstrations of contemporary approaches in behavioral neuroscience.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 426', 'LABORATORY IN BEHAVIORAL NEUROSCIENCE', '9854', 'Closed', 'TuF Tuesday, Friday 1:00 PM–4:30 PM', 'PY 482', 'Preston Garraghty', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experiments with and demonstrations of contemporary approaches in behavioral neuroscience.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 426', 'LABORATORY IN BEHAVIORAL NEUROSCIENCE', '9855', 'Closed', 'WF Wednesday, Friday 1:00 PM–4:30 PM', 'PY 482', 'Preston Garraghty', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experiments with and demonstrations of contemporary approaches in behavioral neuroscience.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 426', 'LABORATORY IN BEHAVIORAL NEUROSCIENCE', '12139', 'Closed', 'Tu Tuesday 9:00 AM–12:00 PM', 'PY 396', 'Natalia Murataeva', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experiments with and demonstrations of contemporary approaches in behavioral neuroscience.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 426', 'LABORATORY IN BEHAVIORAL NEUROSCIENCE', '30078', 'Closed', 'M Monday 9:00 AM–11:30 AM', 'PY 286', 'Ehren Newman', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experiments with and demonstrations of contemporary approaches in behavioral neuroscience.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 429', 'LABORATORY IN DEVELOPMENTAL PSYCHOLOGY', '12419', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PY 286', 'Tongyao Zhang', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Research methods in developmental psychology and their application to selected problems in the development of humans and of nonhuman species.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 435', 'LABORATORY IN HUMAN LEARNING AND COGNITION', '9673', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PY 286', 'Samuel Nordli', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experimental studies of human learning and cognitive processes.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 435', 'LABORATORY IN HUMAN LEARNING AND COGNITION', '12140', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PY 286', 'Oyku Uner', 0, NULL, 'Laboratory', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Experimental studies of human learning and cognitive processes.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 437', 'NEUROBIOLOGY OF ADDICTIONS', '32622', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PY 109', 'Joseph Farley', 3, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'The course provides an in-depth look at the neurobiological bases of addictions, from the cellular, molecular, and systems neuroscience levels of analysis.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PSY-P 448', 'SOCIAL JUDGMENT AND PERSON PERCEPTION', '13529', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PY 230', 'Robert Rydell', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Judgments, decisions, and perceptions of a social nature include self-knowledge, judgments of causality, biases and errors of social judgment such as stereotyping, and the relation of thinking and feeling. Principles will be considered in the context of applied areas such as law and psychotherapy.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 453', 'DECISION-MAKING AND THE BRAIN', '13530', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PY 228', 'Joshua Brown', 2, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'An exploration of how individuals make decisions and what different parts of the brain contribute to decision-making. Focuses on the cognitive psychology of decision-making and on exciting recent advances in the cognitive neuroscience of decision-making, including the new field of neuroeconomics.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 456', 'REPRODUCTIVE NEUROSCIENCE', '30079', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PY 228', 'Heather Bradshaw', 9, NULL, 'Seminar', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Recent and historical literature in the field of reproductive neuroscience. Includes information about sexual differentiation of the brain during development and puberty, sexual differentiation of the neurophysiology of the reproductive tract, decision making in sexual context, and human studies of sexuality. Develops skills to critically evaluate basic scientific literature and develop presentations.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '10099', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PY 228', 'Krista Wisner', 3, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '10115', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PY 230', 'Norbert Hajos', 7, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '30080', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PY 111', 'Kristi DeBoeuf', 12, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '30083', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PY 230', 'William Hetrick', 9, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '32827', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PY 226', 'Frederick Ernst', 1, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '13532', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PY 120A', 'Anne Krendl', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '13534', 'Closed', 'MWF Monday, Wednesday, Friday 3:10 PM–4:00 PM', 'PY 111', 'Irene Vlachos-Weber', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '30081', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PY 230', 'Kristi DeBoeuf', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '30082', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PY 120A', 'Emma Schiestl', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 457', 'TOPICS IN PSYCHOLOGY', '14281', 'Closed', NULL, 'WB WEB', 'Ellen Ratajack', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('PSY-P 466', 'MOLECULAR AND CELLULAR NEUROBIOLOGY', '30085', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PY 111', 'Anne Prieto', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Introduction to the cellular and molecular processes that give the nervous system its unique character. Covers the cell biology of neurons and glia and mechanisms of synaptic plasticity. Examines the genetic and molecular approaches to the biological basis for higher brain functions such as learning and memory.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PSY-P 469', 'STRESS EFFECTS ON BRAIN AND BEHAVIOR', '30086', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PY 230', 'Cara Wellman', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'This seminar examines the neurobiology of stress effects on cognition, psychopathology, and health, from the cellular to the systems level. Through readings from primary literature, discussions, and lectures, students will develop a base of knowledge and think critically about the neural and behavioral effects of stress.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 473', 'LABORATORY IN MOLECULAR NEUROSCIENCE', '5513', 'Class Status', 'TuTh Tuesday, Thursday 3:00 PM–8:00 PM', 'PY 396', 'Cary Lai', 9, NULL, 'Laboratory', '4', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Laboratory course designed to provide the advanced undergraduate with training in molecular techniques useful for studying the nervous system. Techniques will include PCR, subcloning, bacterial transformation, mammalian cell transfection, working with fluorescent proteins, RNA interference, Western blotting and sectioning/staining brain tissues.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 478', 'STEREOTYPING, PREJUDICE, AND DISCRIMINATION', '12151', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PY 230', 'Kurt Hugenberg', 0, NULL, 'Seminar', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'This advanced seminar consists primarily of discussion of recently published journal articles on stereotyping and prejudice. Discussion topics include why people stereotype; how stereotypes and prejudice affect both targets and perceivers; how people might overcome the pernicious effects of stereotypes, prejudice, and discrimination.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 483', 'CLINICAL SUPERVISION AND SKILL ACQUISITION', '8064', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PY 120A', 'Emma Schiestl', 1, NULL, 'Discussion', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Students acquire evidence-based knowledge and skills to enhance competence in work applications (e.g., field experiences, service learning, research labs) in the clinical psychological sciences. Through readings, written assignments, exams, classroom activities, group and individually supervised tasks, students learn how to apply knowledge and skills to their work.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 499', 'HONORS THESIS RESEARCH', '2916', 'Class Status', 'Th Thursday 2:20 PM–3:35 PM', 'PY 128', 'Dale Sengelaub', 11, NULL, 'Seminar', '1–12', 'PSYCHOLOGY', ARRAY[]::TEXT[], NULL, ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('PSY-P 553', 'ADVANCED STATISTICS IN PSYCHOLOGY I', '5986', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PY 111', 'Robert Nosofsky', 7, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Statistical inference applied to problems in psychological research. Experimental design and data interpretation. Elementary probability theory, statistical distributions, classical and non-parametric tests of hypotheses, point and interval estimation. Relations between statistical models and experimental controls.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 595', 'FIRST-YEAR RESEARCH SEMINAR', '2917', 'Class Status', 'W Wednesday 1:30 PM–4:00 PM', 'PY 128', 'Karin James', 5, NULL, 'Seminar', '2–3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Presentation and discussion of first-year, graduate student research projects.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 624', 'PRINCIPLES OF PSYCHOPATHOLOGY', '30087', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PY 115', 'Alexandra Moussa-Tooks', 4, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Description of the phenomena of psychopathology and principles associated with their classification.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 650', 'NEUROIMAGING: THEORY AND METHODS', '30088', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PY 120A', 'Tom James', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Covers theory and methods of neuro-imaging with a particular emphasis on functional MRI. Specific topics include experimental design, data acquisition, data analysis, data interpretation and data presentation. Also covers introductory MR physics and the physiology of blood oxygen-level dependent (BOLD) changes.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 657', 'TOPICAL SEMINAR', '10693', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PY 230', 'Norbert Hajos', 5, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('PSY-P 657', 'TOPICAL SEMINAR', '11231', 'Class Status', 'F Friday 9:00 AM–11:30 AM', 'PY 128', 'Krista Wisner', 30, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('PSY-P 657', 'TOPICAL SEMINAR', '13541', 'Class Status', 'MW Monday, Wednesday 8:20 AM–10:50 AM', 'PY 109', 'Istvan Katona', 5, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('PSY-P 657', 'TOPICAL SEMINAR', '6651', 'Class Status', 'TuTh Tuesday, Thursday 3:00 PM–8:00 PM', 'PY 396', 'Cary Lai', 1, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
