    ('PSY-P 690', 'PRACTICUM IN CLINICAL PSYCHOLOGY', '6039', 'Class Status', 'W Wednesday 11:00 AM–1:00 PM', 'PY 137C', 'Natasha Hansen', 9, NULL, 'Practicum', '1–6', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Community behavioral health clinical practicums.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 690', 'PRACTICUM IN CLINICAL PSYCHOLOGY', '14422', 'Class Status', 'M Monday 11:00 AM–1:00 PM', 'PY 137C', 'Natasha Hansen', 4, NULL, 'Practicum', '1–6', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Community behavioral health clinical practicums.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 690', 'PRACTICUM IN CLINICAL PSYCHOLOGY', '7859', 'Closed', NULL, NULL, 'Peter Finn', 0, NULL, 'Practicum', '1–6', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Community behavioral health clinical practicums.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 700', 'RESEARCH AND THEORY IN SOCIAL PSYCHOLOGY', '8166', 'Class Status', 'F Friday 12:30 PM–1:45 PM', 'PY 128', 'Edward Hirt', 27, NULL, 'Seminar', '0–2', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Four semesters required for graduate students in Social Psychology. Meets weekly. Invited speakers will sometimes present colloquia. Students taking the course for 1 credit will be required to participate in discussions and readings. For 2 credits, students will be required to make a presentation. Mostly, students will present their own research.', ARRAY[]::TEXT[], NULL),
    ('PSY-P 701', 'RESEARCH AND THEORY IN DEVELOPMENTAL SCIENCE', '5948', 'Class Status', 'F Friday 2:30 PM–3:30 PM', 'PY 128', 'Emily Fyfe', 24, NULL, 'Seminar', '1', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Four semesters required for Ph.D. Students in Developmental Psychology. Meets weekly. All students must present at least once a semester. Most will present their own research.', ARRAY[]::TEXT[], NULL),
