    ('PSY-Y 412', 'PSYCHOLOGY AND NEUROSCIENCE OF AUTISM', '30091', 'Class Status', 'F Friday 9:00 AM–11:30 AM', 'PY 120A', 'Dan Kennedy', 7, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Provides an in-depth survey of autism research and controversies, with a focus both on its history and current research developments. Examines its biological bases, prevalence estimates, diagnostic approaches, developmental changes, approaches to intervention, and various additional topics.', ARRAY[]::TEXT[], NULL),
    ('PSY-Y 414', 'THE CONNECTED BRAIN', '30092', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PY 111', 'Olaf Sporns', 0, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Focuses on current knowledge of how the brain is connected, and how these patterns of connectivity underpin behavior and cognition. Covers basic network science, computational network models, connectomics, functional connectivity, resting state, task-evoked connectivity, and how disruptions of connectivity relate to brain disorders.', ARRAY[]::TEXT[], NULL),
    ('PSY-Y 427', 'MOLECULAR, CELLULAR, AND CIRCUIT MECHANISMS OF ADDICTION I: FOUNDATIONS', '30089', 'Class Status', 'MW Monday, Wednesday 8:20 AM–10:50 AM', 'PY 109', 'Istvan Katona', 20, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Looks at how adaptive plasticity processes manifest at the molecular, cellular, and circuit levels and orchestrate appropriate behavioral responses in the ever-changing environment. Considers how chemical substances and behavioral stimuli hijack these processes and elicit maladaptive behavioral responses leading to addiction. Examines the neurobiological basis of these plasticity processes.', ARRAY[]::TEXT[], NULL),
