    ('REL-B 300', 'STUDIES IN SOUTH EAST AND ASIAN RELIGIONS', '37183', 'Class Status', 'MW Monday, Wednesday 9:10 AM–11:40 AM', 'SY 004', 'Richard Nance', 10, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Selected topics and movements in South and East Asian religions.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('REL-C 401', 'TOPICS IN AMERICAN RELIGIOUS HISTORY', '29346', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SB 138', 'Cooper Harriss', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'A selected topic such as American Catholicism in the twentieth century, religion and nationalism in America, or the problem of race and the American churches.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('REL-C 402', 'RELIGION, ILLNESS, AND HEALING', '29348', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'BH 146', 'Candy Brown', 1, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'What is the meaning of illness and healing? Is religion good or bad for health? How should healthcare providers respond to patients'' religious beliefs? What is the relationship between complementary and alternative medicine or prayer and religions such as Hinduism, Buddhism, Taoism, or Christianity? This course is ideal for pre-med, pre-law, business/management, and other interested students.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
