    ('REL-G 599', 'THESIS RESEARCH', '3090', 'Class Status', NULL, NULL, 'Sarah Imhoff', 10, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
